Expanded the testcase a bit:

Imagine this being a hyper server. Every http request has to be mapped to a rust future. In our case, that future can depend on a javascript promise being fulfilled.

```
use deno_core::url::Url;
use deno_core::v8;
use deno_core::JsRuntime;
use deno_core::NoopModuleLoader;
use deno_runtime::permissions::Permissions;
use deno_runtime::worker::MainWorker;
use deno_runtime::worker::WorkerOptions;
use deno_runtime::BootstrapOptions;
use futures::pin_mut;
use futures::stream::FuturesUnordered;
use futures::StreamExt;
use std::cell::RefCell;
use std::future::Future;
use std::pin::Pin;
use std::rc::Rc;
use std::sync::Arc;
use std::task::Context;
use std::task::Poll;
use tokio;

fn get_js_promise(runtime: &mut JsRuntime) -> v8::Global<v8::Value> {
    runtime
        .execute_script(
            "test",
            r#"
new Promise(resolve => setTimeout(resolve, 1000))
"#,
        )
        .unwrap()
}

// Each user request produces a promise. We have to wait for that in
// rust, so we create a future for each JS promise. There can be many
// requests, so the futures are stored on a FuturesUnordered or
// equivalent (not sure what exactly hyper user under the hood).
struct MyFuture {
    js_promise: v8::Global<v8::Value>,
    worker: Rc<RefCell<MainWorker>>,
}

impl Future for MyFuture {
    type Output = anyhow::Result<v8::Global<v8::Value>>;
    fn poll(self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Self::Output> {
        let mut borrow = self.worker.borrow_mut();
        let runtime = &mut borrow.js_runtime;

        // FIXME: propose having a runtime::poll_promise in deno.
        let fut = runtime.resolve_value(self.js_promise.clone());
        pin_mut!(fut);
        let ret = fut.poll(cx);
        println!("espindola {} {:?} {:?}", line!(), self.js_promise, ret);
        ret
    }
}

async fn get_fut(worker: Rc<RefCell<MainWorker>>) {
    let js_promise = {
        let mut borrow = worker.borrow_mut();
        get_js_promise(&mut borrow.js_runtime)
    };
    MyFuture {
        js_promise,
        worker: worker.clone(),
    }
    .await
    .unwrap();
}

#[tokio::main]
async fn main() -> anyhow::Result<()> {
    let module_loader = Rc::new(NoopModuleLoader);
    let create_web_worker_cb = Arc::new(|_| {
